export const HOOK_SOURCES: Record<string, string> = {
  "r2s-ascending": "# R2S — ascending hook (from songs/R2S-sheep-quick-lose.abc bars 3-4)\n#\n# Format: scale-degree notation. Each line is one bar; durations in beats.\n# Degrees: 1-7 within the bed's mode (1 = tonic). Octave shifts: ^1 (up), ,1 (down).\n# Rests: r:dur. Default duration: 1 beat.\n#\n# This hook is ~2 bars. Each bed slot will reference it as %HOOK_*%.\n\n=== r2s-ascending ===\ncharacter: lyrical\nbars: 2\n\n# Bar 1: 1 2 3/4/ 5  → G A B/c/ d in G major (degree 1=G)\n1:1 2:1 3:0.5 4:0.5 5:1\n\n# Bar 2: 6 (3-tied) 5  → e3 d (e dotted-half, d quarter)\n6:3 5:1\n",
  "wolf-call": "# Wolf signature hook — modeled on R6W-wolf-lose's horn-call cell\n# (`E,3/2 B,/ G D` and recurrences across the catalogue piece).\n#\n# Distinct from the sheep hook (r2s-ascending) in two key ways:\n#   - DOWNWARD trajectory (1 → low-5 → 3 → low-7) vs the sheep's upward 1-2-3-4-5\n#   - STARTS with a leap (1.5 → 0.5) vs the sheep's stepwise ascent\n# Round 3 found the wolf hook needed a clearly-different gestural shape so\n# wolf-perspective beds don't sound like the sheep set in minor.\n#\n# Scale degrees in natural minor: 1 = root, 5 = perfect-5th, ,5 = below-octave\n# 5th, 3 = b3, ,7 = below-octave b7. Resolves cleanly in E minor as\n#   E - B(low) - G - D | E(low) - B(low) - low fall\n\n=== wolf-call ===\ncharacter: stalking\nbars: 2\n1:1.5 ,5:0.5 3:1 ,7:1\n,1:2 ,5:2\n",
};

